42	    );
43	    port (
44	        -- Control Ports
45	        Clk         : in    std_logic := '0';
46	        Rst         : in    std_logic := '0';
47	        -- Input
48	        In_Valid    : in    std_logic := '1';
49	        In_Data     : in    std_logic_vector(Width_g-1 downto 0);
50	        -- Output
51	        Out_Valid   : out   std_logic;
52	        Out_Data    : out   std_logic_vector(Width_g-1 downto 0)
53	    );
54	end entity;
