57	
58	    -- Types
59	    type Data_t is array (0 to Stages_g-1) of std_logic_vector(In_Data'range);
60	
61	    -- Signals
62	    signal Data  : Data_t;
63	    signal Valid : std_logic_vector(0 to Stages_g-1);
64	
65	begin
66	
67	    -- ** No reg **
68	    g_noreg : if Stages_g = 0 generate
69	        Out_Valid <= In_Valid;
70	        Out_Data  <= In_Data;
71	    end generate;
72	
73	    -- ** Registers ***
74	    g_reg : if Stages_g > 0 generate
75	
76	        p_reg : process (Clk) is
77	        begin
78	            if rising_edge(Clk) then
79	                -- First stage
80	                Data(0)  <= In_Data;
81	                Valid(0) <= In_Valid;
82	
83	                -- Other stages
84	                for stg in 1 to Stages_g-1 loop
85	                    Data(stg)  <= Data(stg-1);
86	                    Valid(stg) <= Valid(stg-1);
87	                end loop;
88	
89	                -- Reset
90	                if Rst = '1' then
91	                    Valid <= (others => '0');
92	                end if;
93	            end if;
94	        end process;
95	
96	        Out_Valid <= Valid(Stages_g-1);
97	        Out_Data  <= Data(Stages_g-1);
